<?php namespace App\Mail; use App\Models\User; use Illuminate\Bus\Queueable; use Illuminate\Mail\Mailable; use Illuminate\Mail\Mailables\Content; use Illuminate\Mail\Mailables\Envelope; use Illuminate\Queue\SerializesModels; class UserCreated extends Mailable { use Queueable, SerializesModels; public $user; public $plainPassword; public function __construct(User $user, $plainPassword) { $this->user = $user; $this->plainPassword = $plainPassword; } public function envelope(): Envelope { return new Envelope(subject: "Bienvenido a Autos Mrini - Acceso al Panel"); } public function content(): Content { return new Content(view: "emails.user_created"); } public function attachments(): array { return []; } }
